(() => {
    type TupleCircular = [Date, number, string, null, string[], bigint, TupleCircular?];
    return {build: () => createValidate<TupleCircular>(), buildErrors: () => noErrs(createGetValidationErrors<TupleCircular>())};
  })()

c(
    Type.Recursive((This) =>
      Type.Union([
        Type.Tuple([Type.Date(), Type.Number(), Type.String(), Type.Null(), Type.Array(Type.String()), Type.BigInt()]),
        Type.Tuple([Type.Date(), Type.Number(), Type.String(), Type.Null(), Type.Array(Type.String()), Type.BigInt(), This]),
      ])
    )
  )

c(z.lazy(() => {
    const schema: z.ZodType = z.custom((v) => {
      if (!Array.isArray(v)) return false;
      if (v.length < 6) return false;
      if (!(v[0] instanceof Date) || isNaN((v[0] as Date).getTime())) return false;
      if (typeof v[1] !== 'number' || !Number.isFinite(v[1])) return false;
      if (typeof v[2] !== 'string') return false;
      if (v[3] !== null) return false;
      if (!Array.isArray(v[4])) return false;
      if (typeof v[5] !== 'bigint') return false;
      if (v.length > 6 && v[6] !== undefined && !schema.safeParse(v[6]).success) return false;
      return true;
    });
    return schema;
  }))
